var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"와아아! 안녕하세요! 이거 정말 방송에 나오는 건가요?!","JPN":"わ～～！　こんにちは！\\nこれ本当に配信されてるんですか！？","ENG":"Wow, hello! Is this really live right now?","TWN":"哇啊啊！大家好！這真的會在廣播裡播出嗎？！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"다, 당황하지 마랏! 베, 베테랑 병사는 총구와 카메라렌즈 따위에 흔들리지 않아!","JPN":"あ、慌てるな！\\nべ、ベテランの兵士は銃口とカメラレンズの前で、戸惑ったりしないものだ！","ENG":"D-don't be nervous! V-veteran soldiers shouldn't be afraid of enemies' guns, or the camera!","TWN":"別、別慌！老兵可不會害怕區區槍口和攝像頭！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"하하! 그러지 말고 손이라도 흔들어 보라니까?","JPN":"そんなカチカチにならなくて大丈夫だよ？\\n手を振ってみようよ！","ENG":"Hah hah! Don't be like that. Why don't you wave your hand at it?","TWN":"哈哈！別這樣啦，和大家招招手怎麼樣？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"예전부터 TV에 나오고 싶어 했잖아.","JPN":"前からTVに出たがってたでしょ～？","ENG":"You've always wanted to be on TV.","TWN":"你不是一直想上電視嘛。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"그, 그건 빛나는 전공을 세운 후 훈장수여식에 나오고 싶다는 뜻이었다, 대장!","JPN":"そ、それは、輝かしい戦功を立てた後、勲章を授与される時の話だ、隊長！","ENG":"T-to receive a medal of merit for my brilliant service, Captain!","TWN":"我、我是說立下光榮戰功後，出現在勳章授予儀式上，隊長！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"귀여운 아이들이군요. 이런 작은 방송 카메라 앞에서도 긴장하다니.","JPN":"かわいい子たちですわね。こんな小さなカメラの前でも緊張するなんて。","ENG":"You guys are cute. You get nervous before such a tiny camera like this.","TWN":"真是群可愛的孩子，在這種小廣播的攝像機前也會緊張啊。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"와, 무지 예쁜 언니다!","JPN":"わあ、美人なお姉さん！","ENG":"Whoa, you're so pretty!","TWN":"哇，好漂亮的姐姐！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"저희 방송은 처음이거든요. 언니는 괜찮아요?","JPN":"僕たち、撮影されるの初めてなんです。お姉さんは平気なんですか？","ENG":"We've never been on a live show before. Aren't you nervous?","TWN":"我們是第一次參加直播嘛，姐姐不會緊張嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"물론 그럴 수 밖에요.","JPN":"もちろんですわ。","ENG":"Absolutely not.","TWN":"當然啦。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"전 어렸을 때부터 이골이 날 정도로 남들의 주목을 받아왔거든요.","JPN":"私は幼い頃から、いやと言うほど周りから注目されてきましたので。","ENG":"I've always been the centre of attention since I was young.","TWN":"我從小時候起就一直受到別人的注目，幾乎都習慣啦。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"그럼 언니도 연예인이에요? 어쩐지!","JPN":"それじゃあ、お姉さんも芸能人なんですか？　やっぱり！","ENG":"Are you a celebrity? I knew it!","TWN":"那姐姐也是藝人嘍？怪不得！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그런 건 아니지만...... 어떤 영감님들에겐 그 비슷한 취급을 받고 있긴 하죠.","JPN":"そういうわけではありませんが……\\n一部の方々には、似たような扱いを受けていますわ。","ENG":"Not exactly, but in a way I am, among some gaffers.","TWN":"也不是……不過對一些老爺子來說也差不多吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"저어...... 인사가 끝났으면 자기소개를 시작해도 될까요?","JPN":"あのう……挨拶が終わったようですので、\\n自己紹介をお願いできますか？","ENG":"Erm, if you're finished saying hello to each other, mind introducing yourselves to our viewers?","TWN":"那個……打過招呼的話可以開始自我介紹了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"앗, 저요! 저요! 저부터 할래요!","JPN":"あ、僕から自己紹介させてください！","ENG":"Ooh, me! Me! Let me go first!","TWN":"啊，我！我！從我開始吧！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"관리국 카운터 아카데미 중등부에 다니고 있는 양하림입니다!","JPN":"管理局のカウンターアカデミー、中等部のホシノ・ウサギです！","ENG":"My name is Yang Harim, and I'm in the Administration's Junior High Academy.","TWN":"我是管理局制裁者學院初中部的楊夏琳！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"여기에 와서 채집을 도와드리면 수행평가 점수에 반영된다고 해서 왔어요!","JPN":"ここで採集のお手伝いをすれば成績に反映されるということなので、\\n手伝いに来ました！","ENG":"I came here to help harvest the fruit and get Performance Appraisal Points.","TWN":"我聽說，來這裡幫忙採集可以反映到個人評估分數裡，所以就過來了！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"그리고 난 같은 곳에서 훈련을 받고 있는 한소림 병장이다.","JPN":"そして本官は、同じ所で訓練を受けている兵長、ハネダ・ミズキだ。","ENG":"I'm Han Sorim, sergeant in the same Academy as she.","TWN":"她是和我在一個地方接受訓練的蕭林兵長。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"병장이요? 소림양은 그...... 군인이라기엔 너무 어리지 않나요?","JPN":"兵長ですか？　ミズキさんは、その……\\n軍人というには、年齢的に無理があると思うのですが……","ENG":"Sergeant? Sorim, but aren't you... a little bit too young to be a soldier?","TWN":"兵長？說蕭林小姐，那個……是軍人的話會不會太年輕了？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};